#include <stdio.h>

/* == RAPPEL =================================================
 * Annale UTC502 1ère session 2021-2022, Exercice 1
 *
 * Avec BLOCK_SIZE=512, PTR_SIZE=4, FILE_SIZE=2Mo :
 *   data_blocks       = 2097152 / 512  = 4096
 *   entries_per_block = 512 / 4        = 128
 *   remaining         = 4096 - 12      = 4084
 *   i1_blocks         = ceil(4084/128) = 32
 *
 * Formule plafond entier : ceil(a/b) = (a + b - 1) / b
 * =========================================================== */

#define BLOCK_SIZE    512
#define PTR_SIZE      4
#define FILE_SIZE     (2 * 1024 * 1024)
#define DIRECT_BLOCKS 12

int main(void) {
    int data_blocks       = FILE_SIZE / BLOCK_SIZE;
    int entries_per_block = BLOCK_SIZE / PTR_SIZE;
    int remaining         = data_blocks - DIRECT_BLOCKS;
    int i1_blocks         = (remaining + entries_per_block - 1) / entries_per_block;

    printf("Blocs de données: %d\n", data_blocks);
    printf("Entrées par bloc indirect: %d\n", entries_per_block);
    printf("Blocs restants après directs: %d\n", remaining);
    printf("Blocs d'indirection simple: %d\n", i1_blocks);
    return 0;
}

